package server

import (
	"context"
	"log"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

type GracefulServer struct {
	httpServer  *http.Server
	ctx         context.Context
	cancel      context.CancelFunc
}

func NewGracefulServer(addr string, handler http.Handler) *GracefulServer {
	ctx, cancel := context.WithCancel(context.Background())
	return &GracefulServer{
		httpServer: &http.Server{
			Addr:         addr,
			Handler:      handler,
			ReadTimeout:  15 * time.Second,
			WriteTimeout: 15 * time.Second,
		},
		ctx:    ctx,
		cancel: cancel,
	}
}

func (s *GracefulServer) Start() error {
	go func() {
		sigChan := make(chan os.Signal, 1)
		signal.Notify(sigChan, syscall.SIGINT, syscall.SIGTERM)
		<-sigChan

		log.Println("Shutting down server...")
		s.cancel()
	}()

	log.Printf("Server starting on %s", s.httpServer.Addr)
	if err := s.httpServer.ListenAndServe(); err != nil && err != http.ErrServerClosed {
		return err
	}

	return nil
}

func (s *GracefulServer) Shutdown(timeout time.Duration) error {
	ctx, cancel := context.WithTimeout(s.ctx, timeout)
	defer cancel()

	log.Println("Waiting for connections to finish...")
	err := s.httpServer.Shutdown(ctx)
	if err != nil {
		log.Printf("Server forced to shutdown: %v", err)
	}

	log.Println("Server stopped")
	return err
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
	})
	mux.HandleFunc("/api/data", func(w http.ResponseWriter, r *http.Request) {
		time.Sleep(2 * time.Second)
		w.Write([]byte("data"))
	})

	server := NewGracefulServer(":8080", mux)
	if err := server.Start(); err != nil {
		log.Fatalf("Server error: %v", err)
	}

	server.Shutdown(30 * time.Second)
}

package context

import (
	"context"
	"fmt"
	"time"
)

type TraceIDKey struct{}

type RequestTracer struct {
	traceID   string
	spanID    string
	parentSpan string
}

func WithTraceID(ctx context.Context, traceID string) context.Context {
	return context.WithValue(ctx, TraceIDKey{}, traceID)
}

func GetTraceID(ctx context.Context) string {
	if tid, ok := ctx.Value(TraceIDKey{}).(string); ok {
		return tid
	}
	return "unknown"
}

func ChildSpan(ctx context.Context, spanName string) (context.Context, *RequestTracer) {
	traceID := GetTraceID(ctx)
	spanID := fmt.Sprintf("%x", time.Now().UnixNano())
	tracer := &RequestTracer{
		traceID:   traceID,
		spanID:    spanID,
		parentSpan: "",
	}

	return context.WithValue(ctx, TraceIDKey{}, traceID), tracer
}

type ServiceClient struct {
	baseURL string
}

func (sc *ServiceClient) CallAPI(ctx context.Context, endpoint string) (string, error) {
	traceID := GetTraceID(ctx)
	fmt.Printf("[TRACE:%s] Calling %s\n", traceID, endpoint)

	resp, err := http.Get(sc.baseURL + endpoint)
	if err != nil {
		return "", err
	}
	defer resp.Body.Close()

	return resp.Body.
}

package health

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"time"
)

type CheckResult struct {
	Name     string `json:"name"`
	Status   string `json:"status"`
	Latency  int64  `json:"latency_ms"`
	Message  string `json:"message,omitempty"`
}

type HealthChecker struct {
	checks map[string]func() CheckResult
}

func NewHealthChecker() *HealthChecker {
	return &HealthChecker{checks: make(map[string]func() CheckResult)}
}

func (hc *HealthChecker) Register(name string, fn func() CheckResult) {
	hc.checks[name] = fn
}

func (hc *HealthChecker) Handler() http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		results := make([]CheckResult, 0)
		var hasError bool

		for name, check := range hc.checks {
			start := time.Now()
			result := check()
			result.Latency = time.Since(start).Milliseconds()

			if result.Status == "error" {
				hasError = true
			}

			results = append(results, result)
		}

		overallStatus := "healthy"
		if hasError {
			overallStatus = "unhealthy"
		}

		w.Header().Set("Content-Type", "application/json")
		if overallStatus == "unhealthy" {
			w.WriteHeader(http.StatusServiceUnavailable)
		}

		json.NewEncoder(w).Encode(map[string]interface{}{
			"status": overallStatus,
			"checks": results,
			"uptime": time.Since(startTime).String(),
		})
	}
}

func main() {
	checker := NewHealthChecker()
	checker.Register("database", func() CheckResult {
		start := time.Now()
		err := db.Ping()
		latency := time.Since(start).Milliseconds()

		if err != nil {
			return CheckResult{Name: "database", Status: "error", Latency: latency, Message: err.Error()}
		}
		return CheckResult{Name: "database", Status: "ok", Latency: latency}
	})

	checker.Register("redis", func() CheckResult {
		start := time.Now()
		err := redis.Ping()
		latency := time.Since(start).Milliseconds()

		if err != nil {
			return CheckResult{Name: "redis", Status: "error", Latency: latency, Message: err.Error()}
		}
		return CheckResult{Name: "redis", Status: "ok", Latency: latency}
	})

	http.Handle("/health", checker.Handler())
	log.Fatal(http.ListenAndServe(":8080", nil))
}

package logging

import (
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
	"os"
)

type Logger struct {
	logger *zap.SugaredLogger
	fields []zap.Field
}

func NewLogger(level string) (*Logger, error) {
	cfg := zap.NewProductionConfig()
	cfg.Level = zap.NewAtomicLevelAt(parseLevel(level))
	cfg.EncoderConfig.TimeKey = "timestamp"
	cfg.EncoderConfig.EncodeTime = zapcore.ISO8601TimeEncoder

	logger, err := cfg.Build()
	if err != nil {
		return nil, err
	}

	return &Logger{logger: logger.Sugar()}, nil
}

func (l *Logger) With(fields ...zap.Field) *Logger {
	newLogger := *l
	newLogger.fields = append(newLogger.fields, fields...)
	return &newLogger
}

func (l *Logger) Info(msg string, args ...interface{}) {
	l.logger.With(l.fields...).Infow(msg, args...)
}

func (l *Logger) Error(msg string, args ...interface{}) {
	l.logger.With(l.fields...).Errorw(msg, args...)
}

func (l *Logger) Debug(msg string, args ...interface{}) {
	l.logger.With(l.fields...).Debugw(msg, args...)
}

func (l *Logger) Warn(msg string, args ...interface{}) {
	l.logger.With(l.fields...).Warnw(msg, args...)
}

func parseLevel(level string) zapcore.Level {
	switch level {
	case "debug":
		return zapcore.DebugLevel
	case "info":
		return zapcore.InfoLevel
	case "warn":
		return zapcore.WarnLevel
	case "error":
		return zapcore.ErrorLevel
	default:
		return zapcore.InfoLevel
	}
}

func main() {
	logger, _ := NewLogger("info")

	reqLogger := logger.With(
		zap.String("requestId", "abc-123"),
		zap.String("userId", "user-456"),
	)

	reqLogger.Info("Processing request", zap.Int("items", 5))
	reqLogger.Error("Request failed", zap.Error(err))
}

package config

import (
	"fmt"
	"strings"

	"github.com/spf13/viper"
)

type Config struct {
	Server   ServerConfig
	Database DatabaseConfig
	Redis    RedisConfig
	Logging  LoggingConfig
}

type ServerConfig struct {
	Host string `mapstructure:"host"`
	Port int    `mapstructure:"port"`
}

type DatabaseConfig struct {
	DSN        string `mapstructure:"dsn"`
	MaxOpenConns int   `mapstructure:"max_open_conns"`
	MaxIdleConns int   `mapstructure:"max_idle_conns"`
}

type RedisConfig struct {
	Addr     string `mapstructure:"addr"`
	Password string `mapstructure:"password"`
}

type LoggingConfig struct {
	Level  string `mapstructure:"level"`
	Format string `mapstructure:"format"`
}

func LoadConfig(configPath string) (*Config, error) {
	viper.SetConfigFile(configPath)
	viper.SetConfigType("yaml")

	viper.AutomaticEnv()
	viper.SetEnvPrefix("APP")
	viper.SetEnvKeyReplacer(strings.NewReplacer(".", "_"))

	viper.SetDefault("server.host", "localhost")
	viper.SetDefault("server.port", 8080)
	viper.SetDefault("database.max_open_conns", 25)
	viper.SetDefault("database.max_idle_conns", 5)
	viper.SetDefault("logging.level", "info")
	viper.SetDefault("logging.format", "json")

	if err := viper.ReadInConfig(); err != nil {
		return nil, fmt.Errorf("failed to read config: %w", err)
	}

	var cfg Config
	if err := viper.Unmarshal(&cfg); err != nil {
		return nil, fmt.Errorf("failed to unmarshal config: %w", err)
	}

	return &cfg, nil
}

func main() {
	cfg, err := LoadConfig("config.yaml")
	if err != nil {
		log.Fatalf("Failed to load config: %v", err)
	}

	fmt.Printf("Server: %s:%d\n", cfg.Server.Host, cfg.Server.Port)
	fmt.Printf("Database DSN: %s\n", cfg.Database.DSN)
	fmt.Printf("Logging Level: %s\n", cfg.Logging.Level)
}

package metrics

import (
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

type MetricsCollector struct {
	requestsTotal   *prometheus.CounterVec
	requestDuration *prometheus.HistogramVec
	activeUsers     prometheus.Gauge
	queueLength     prometheus.Gauge
}

func NewMetricsCollector() *MetricsCollector {
	return &MetricsCollector{
		requestsTotal: promauto.NewCounterVec(prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		}, []string{"method", "endpoint", "status"}),

		requestDuration: promauto.NewHistogramVec(prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		}, []string{"method", "endpoint"}),

		activeUsers: promauto.NewGauge(prometheus.GaugeOpts{
			Name: "active_users",
			Help: "Current number of active users",
		}),

		queueLength: promauto.NewGauge(prometheus.GaugeOpts{
			Name: "job_queue_length",
			Help: "Current length of the job queue",
		}),
	}
}

func (mc *MetricsCollector) Middleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		start := time.Now()

		mw := &statusResponseWriter{ResponseWriter: w, statusCode: http.StatusOK}
		next.ServeHTTP(mw, r)

		mc.requestsTotal.WithLabelValues(r.Method, r.URL.Path, fmt.Sprintf("%d", mw.statusCode)).Inc()
		mc.requestDuration.WithLabelValues(r.Method, r.URL.Path).Observe(time.Since(start).Seconds())
	})
}

type statusResponseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (w *statusResponseWriter) WriteHeader(code int) {
	w.statusCode = code
	w.ResponseWriter.WriteHeader(code)
}

func SetupPrometheusEndpoint(metrics *MetricsCollector, port int) {
	http.Handle("/metrics", promhttp.Handler())
	metrics.activeUsers.Set(0)
}

package retry

import (
	"fmt"
	"math/rand"
	"time"
)

type BackoffConfig struct {
	InitialDelay time.Duration
	MaxDelay     time.Duration
	Multiplier   float64
	MaxRetries   int
	Jitter       bool
}

func DefaultBackoffConfig() BackoffConfig {
	return BackoffConfig{
		InitialDelay: 1 * time.Second,
		MaxDelay:     30 * time.Second,
		Multiplier:   2.0,
		MaxRetries:   3,
		Jitter:       true,
	}
}

func ExponentialBackoff(config BackoffConfig, operation func() error) error {
	var delay time.Duration

	for attempt := 0; attempt <= config.MaxRetries; attempt++ {
		if attempt > 0 {
			delay = calculateDelay(config, attempt)
			time.Sleep(delay)
		}

		err := operation()
		if err == nil {
			return nil
		}

		if attempt == config.MaxRetries {
			return fmt.Errorf("operation failed after %d retries: %w", config.MaxRetries, err)
		}
	}

	return nil
}

func calculateDelay(config BackoffConfig, attempt int) time.Duration {
	delay := time.Duration(float64(config.InitialDelay.Nanoseconds()) * math.Pow(config.Multiplier, float64(attempt-1)))

	if delay > config.MaxDelay {
		delay = config.MaxDelay
	}

	if config.Jitter {
		randomFactor := 0.5 + rand.Float64()*0.5
		delay = time.Duration(float64(delay.Nanoseconds()) * randomFactor)
	}

	return delay
}

func main() {
	config := DefaultBackoffConfig()
	err := ExponentialBackoff(config, func() error {
		// Simulate flaky API call
		if time.Now().Unix()%2 == 0 {
			return fmt.Errorf("temporary error")
		}
		return nil
	})

	if err != nil {
		fmt.Printf("Final error: %v\n", err)
	}
}

package ratelimit

import (
	"sync"
	"time"
)

type TokenBucket struct {
	tokens     float64
	maxTokens  float64
	refillRate float64 // tokens per second
	lastRefill time.Time
	mu         sync.Mutex
}

func NewTokenBucket(maxTokens float64, refillRate float64) *TokenBucket {
	return &TokenBucket{
		tokens:     maxTokens,
		maxTokens:  maxTokens,
		refillRate: refillRate,
		lastRefill: time.Now(),
	}
}

func (tb *TokenBucket) Allow() bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	now := time.Now()
	elapsed := now.Sub(tb.lastRefill).Seconds()
	tb.tokens += elapsed * tb.refillRate
	if tb.tokens > tb.maxTokens {
		tb.tokens = tb.maxTokens
	}
	tb.lastRefill = now

	if tb.tokens >= 1.0 {
		tb.tokens -= 1.0
		return true
	}
	return false
}

func (tb *TokenBucket) AllowN(n int) bool {
	tb.mu.Lock()
	defer tb.mu.Unlock()

	tb.refill()

	if tb.tokens >= float64(n) {
		tb.tokens -= float64(n)
		return true
	}
	return false
}

func (tb *TokenBucket) refill() {
	now := time.Now()
	elapsed := now.Sub(tb.lastRefill).Seconds()
	tb.tokens += elapsed * tb.refillRate
	if tb.tokens > tb.maxTokens {
		tb.tokens = tb.maxTokens
	}
	tb.lastRefill = now
}

func (tb *TokenBucket) AvailableTokens() float64 {
	tb.mu.Lock()
	defer tb.mu.Unlock()
	tb.refill()
	return tb.tokens
}

func main() {
	bucket := NewTokenBucket(10.0, 2.0) // 10 max, refills at 2/sec

	for i := 0; i < 12; i++ {
		if bucket.Allow() {
			fmt.Printf("Request %d: allowed\n", i+1)
		} else {
			fmt.Printf("Request %d: rate limited\n", i+1)
		}
		time.Sleep(100 * time.Millisecond)
	}
}
